440	+    const slug = result.frontmatter.title
441	+      .toLowerCase()
442	+      .replace(/[^a-z0-9]+/g, '-')
443	+      .replace(/^-|-$/g, '')
444	+      .slice(0, 60);
445	+    const filename = `${slug || 'dispatch-post'}.md`;
446	+    const blob = new Blob([result.markdown], { type: 'text/markdown' });
447	+    const url = URL.createObjectURL(blob);
448	+    const a = document.createElement('a');
449	+    a.href = url;
450	+    a.download = filename;
451	+    a.click();
452	+    URL.revokeObjectURL(url);
453	+    toast.success(`Downloaded ${filename}`);
454	+  }
