463	+          <TabsList variant="default" className="h-8">
464	+            <TabsTrigger value="preview" className="text-xs px-3">Preview</TabsTrigger>
465	+            <TabsTrigger value="markdown" className="text-xs px-3">Markdown</TabsTrigger>
466	+          </TabsList>
467	+        </Tabs>
468	+        <div className="flex items-center gap-1.5">
469	+          <span className="text-xs text-muted-foreground">{result.wordCount} words</span>
470	+          <Button variant="outline" size="sm" className="h-7 gap-1.5 text-xs" onClick={handleCopy}>
471	+            {copied ? <Check className="h-3.5 w-3.5" /> : <Copy className="h-3.5 w-3.5" />}
472	+            {copied ? 'Copied' : 'Copy'}
473	+          </Button>
474	+          <Button variant="outline" size="sm" className="h-7 gap-1.5 text-xs" onClick={handleDownload}>
475	+            <Download className="h-3.5 w-3.5" />
476	+            Download .md
477	+          </Button>
478	+        </div>
479	+      </div>
480	+
481	+      {result.frontmatter.tldr && (
482	+        <div className="mx-4 mt-3 px-3 py-2 rounded-md bg-muted/50 border text-sm text-muted-foreground shrink-0">
483	+          <span className="font-medium text-foreground">TL;DR:</span> {result.frontmatter.tldr}
484	+        </div>
485	+      )}
486	+
487	+      <div className="flex-1 overflow-y-auto px-4 py-3">
488	+        {tab === 'preview' ? (
489	+          <div className="prose prose-sm dark:prose-invert max-w-none">
490	+            <ReactMarkdown remarkPlugins={[remarkGfm]}>
491	+              {bodyOnly}
492	+            </ReactMarkdown>
493	+          </div>
494	+        ) : (
495	+          <pre className="text-xs font-mono whitespace-pre-wrap break-words text-muted-foreground">
496	+            {result.markdown}
497	+          </pre>
498	+        )}
499	+      </div>
500	+    </div>
501	+  );
502	+}
