1058	+// Prompt construction and output parsing for the Dispatch blog post generator.
1059	+
1060	+import type { DispatchTone, DispatchInsight } from '@code-insights/cli/types';
1061	+
1062	+// --- System prompt ---
1063	+
1064	+const TONE_INSTRUCTIONS: Record<DispatchTone, string> = {
1065	+  'technical': 'Write for senior engineers. Precise vocabulary, specific trade-offs, do not over-explain fundamentals. Favor depth over accessibility.',
1066	+  'accessible': 'Write for a mixed technical and non-technical audience. Define terms on first introduction, use analogies where helpful, keep sentences short. Favor clarity over density.',
1067	+  'quick-tips': 'Write in a tips format. Each body section opens with a bold actionable tip, followed by 2-4 sentences of context. Favor scanability over narrative.',
1068	+};
1069	+
1070	+const SYSTEM_PROMPT_BASE = `You are a technical ghostwriter helping a software engineer publish their learnings.
1071	+The engineer has selected specific learnings and provided context about the story.
1072	+
1073	+Write a blog post of 800-1000 words in markdown (body only, excluding frontmatter).
1074	+Structure: opening paragraph, 2-4 body sections each with an H2 heading, closing takeaway paragraph.
1075	+Use plain, direct prose — write like an engineer sharing hard-won knowledge, not a content marketer.
1076	+Do not use the words: "leveraged", "utilized", "seamlessly", "delve".
1077	+Do not invent facts not present in the insights.
1078	+Do not mention AI coding sessions, Code Insights, or any tool names.
1079	+Synthesize — do not enumerate insights one by one as a list.
1080	+
1081	+Output a markdown document only — no preamble, no meta-commentary.
1082	+Begin with a YAML frontmatter block in exactly this format:
1083	+---
1084	+title: "A concise title (10 words max)"
1085	+tags: [tag1, tag2, tag3]
1086	+tldr: "One sentence summary of the post"
1087	+---
1088	+
1089	+Then write the blog post body (H2 sections, no H1 — title is in the frontmatter).`;
1090	+
1091	+export function buildDispatchSystemPrompt(tone: DispatchTone): string {
1092	+  return `${SYSTEM_PROMPT_BASE}\n\n${TONE_INSTRUCTIONS[tone]}`;
1093	+}
1094	+
1095	+// --- User context builder ---
1096	+
1097	+export interface DispatchInput {
1098	+  userContext: string;
1099	+  insights: DispatchInsight[];
1100	+}
1101	+
1102	+export function buildDispatchContext(input: DispatchInput): string {
1103	+  const insightBlocks = input.insights.map((insight, i) => {
1104	+    const typeLabel = insight.type.charAt(0).toUpperCase() + insight.type.slice(1);
1105	+    const wordCount = insight.content.split(' ').length;
1106	+    const bulletLines = wordCount < 40 && insight.bullets.length > 0
1107	+      ? '\n' + insight.bullets.map(b => `- ${b}`).join('\n')
1108	+      : '';
1109	+    return `[${typeLabel.toUpperCase()} ${i + 1}]\nSummary: ${insight.summary}\n${insight.content}${bulletLines}`;
1110	+  });
1111	+
1112	+  return `Context from the author:\n${input.userContext}\n\n---\n\nINSIGHTS (${input.insights.length} selected by author):\n\n${insightBlocks.join('\n\n')}`;
1113	+}
1114	+
1115	+// --- Output parser ---
1116	+
1117	+export interface DispatchParseResult {
1118	+  ok: boolean;
1119	+  markdown?: string;
1120	+  frontmatter?: {
1121	+    title: string;
1122	+    tags: string[];
1123	+    tldr: string;
1124	+  };
1125	+  error?: 'missing-frontmatter' | 'malformed-frontmatter';
1126	+  raw?: string;
1127	+}
1128	+
1129	+const PROHIBITED_WORDS = ['leveraged', 'utilized', 'seamlessly', 'delve'];
1130	+
1131	+export function parseDispatchOutput(raw: string): DispatchParseResult {
1132	+  const fmMatch = raw.match(/^[\s]*---\n([\s\S]*?)\n---\n([\s\S]*)$/);
1133	+  if (!fmMatch) {
1134	+    return { ok: false, error: 'missing-frontmatter', raw };
1135	+  }
1136	+
1137	+  const fm = fmMatch[1];
1138	+  const body = fmMatch[2].trim();
1139	+
1140	+  const titleMatch = fm.match(/^title:\s*"?(.+?)"?\s*$/m);
1141	+  const tldrMatch = fm.match(/^tldr:\s*"?(.+?)"?\s*$/m);
1142	+  const tagsMatch = fm.match(/^tags:\s*\[(.+?)\]/m);
1143	+
1144	+  if (!titleMatch || !tldrMatch) {
1145	+    return { ok: false, error: 'malformed-frontmatter', raw };
1146	+  }
1147	+
1148	+  const tags = tagsMatch
1149	+    ? tagsMatch[1].split(',').map(t => t.trim().replace(/^['"]|['"]$/g, ''))
1150	+    : [];
1151	+
1152	+  // Detect truncation — body should end with a sentence terminator
1153	+  const trimmedBody = body.trim();
1154	+  if (trimmedBody.length > 0 && !/[.!?]$/.test(trimmedBody)) {
1155	+    console.warn('[dispatch-truncation] Generated post may be truncated — does not end with sentence terminator');
1156	+  }
1157	+
1158	+  // Log prohibited word leakage without rejecting
1159	+  const lowerBody = body.toLowerCase();
1160	+  const found = PROHIBITED_WORDS.filter(w => lowerBody.includes(w));
1161	+  if (found.length > 0) {
1162	+    console.warn(`[dispatch-prohibited-words] Prohibited words found in output: ${found.join(', ')}`);
1163	+  }
1164	+
1165	+  // Reconstruct full markdown with frontmatter
1166	+  const markdown = `---\ntitle: ${titleMatch[1]}\ntags: [${tags.join(', ')}]\ntldr: ${tldrMatch[1]}\n---\n\n${body}`;
1167	+
1168	+  return {
1169	+    ok: true,
1170	+    markdown,
1171	+    frontmatter: {
1172	+      title: titleMatch[1],
1173	+      tags,
1174	+      tldr: tldrMatch[1],
1175	+    },
1176	+  };
1177	+}
1178	+
1179	+// Degrade gracefully when both the initial parse and retry fail.
1180	+// Extracts H1 as title if present, otherwise uses 'Untitled'.
1181	+export function buildDegradedResponse(raw: string): DispatchParseResult {
1182	+  const h1Match = raw.match(/^#+\s+(.+)$/m);
1183	+  const title = h1Match ? h1Match[1] : 'Untitled';
1184	+  return {
1185	+    ok: true,
1186	+    markdown: raw,
1187	+    frontmatter: {
1188	+      title,
1189	+      tags: [],
1190	+      tldr: '',
1191	+    },
1192	+  };
1193	+}
