1200	+import { Hono } from 'hono';
1201	+import { getDb } from '@code-insights/cli/db/client';
1202	+import { createLLMClient } from '../llm/client.js';
1203	+import { requireLLM } from './route-helpers.js';
1204	+import {
1205	+  buildDispatchSystemPrompt,
1206	+  buildDispatchContext,
1207	+  parseDispatchOutput,
1208	+  buildDegradedResponse,
1209	+} from '../llm/dispatch-prompts.js';
1210	+import type { DispatchTone, DispatchInsight } from '@code-insights/cli/types';
1211	+
1212	+const app = new Hono();
1213	+
1214	+const VALID_TONES: DispatchTone[] = ['technical', 'accessible', 'quick-tips'];
1215	+
1216	+interface InsightRow {
1217	+  id: string;
1218	+  type: string;
1219	+  summary: string;
1220	+  content: string;
1221	+  bullets: string; // JSON-encoded string[]
1222	+}
1223	+
1224	+function countWords(text: string): number {
1225	+  const bodyMatch = text.match(/---[\s\S]*?---\n([\s\S]*)/);
1226	+  const body = bodyMatch ? bodyMatch[1] : text;
1227	+  return body.trim().split(/\s+/).filter(Boolean).length;
1228	+}
1229	+
1230	+// POST /api/dispatch/generate
1231	+// Body: { insightIds: string[], context: string, tone: DispatchTone }
1232	+// Returns: { markdown, frontmatter: { title, tags, tldr }, wordCount, model, tokensUsed }
1233	+app.post('/generate', requireLLM(), async (c) => {
1234	+  const body = await c.req.json<{
1235	+    insightIds?: unknown;
1236	+    context?: unknown;
1237	+    tone?: unknown;
1238	+  }>();
1239	+
1240	+  // Validate insightIds
1241	+  if (!Array.isArray(body.insightIds)) {
1242	+    return c.json({ error: 'insightIds must be an array' }, 400);
1243	+  }
1244	+  const insightIds = body.insightIds as unknown[];
1245	+  if (insightIds.some((id) => typeof id !== 'string')) {
1246	+    return c.json({ error: 'insightIds must contain only strings' }, 400);
1247	+  }
1248	+  if (insightIds.length < 3) {
1249	+    return c.json({ error: 'Select at least 3 insights to generate a post' }, 400);
1250	+  }
1251	+  if (insightIds.length > 8) {
1252	+    return c.json({ error: 'For the best post, keep it to 8 or fewer insights' }, 400);
1253	+  }
1254	+
1255	+  // Validate context
1256	+  if (typeof body.context !== 'string' || body.context.trim().length === 0) {
1257	+    return c.json({ error: 'context is required' }, 400);
1258	+  }
1259	+  if (body.context.length > 500) {
1260	+    return c.json({ error: 'context must be 500 characters or fewer' }, 400);
1261	+  }
1262	+
1263	+  // Validate tone
1264	+  if (!VALID_TONES.includes(body.tone as DispatchTone)) {
1265	+    return c.json({ error: `tone must be one of: ${VALID_TONES.join(', ')}` }, 400);
1266	+  }
1267	+
1268	+  const tone = body.tone as DispatchTone;
1269	+  const contextText = body.context.trim();
1270	+  const typedIds = insightIds as string[];
1271	+
1272	+  // Fetch insights from DB — respects provided order
1273	+  const db = getDb();
1274	+  const placeholders = typedIds.map(() => '?').join(', ');
1275	+  const rows = db.prepare(
1276	+    `SELECT id, type, summary, content, bullets FROM insights WHERE id IN (${placeholders})`
1277	+  ).all(...typedIds) as InsightRow[];
1278	+
1279	+  if (rows.length === 0) {
1280	+    return c.json({ error: 'No insights found for the provided IDs' }, 404);
1281	+  }
1282	+
1283	+  // Preserve the caller's ordering
1284	+  const rowMap = new Map(rows.map((r) => [r.id, r]));
1285	+  const orderedInsights: DispatchInsight[] = typedIds
1286	+    .map((id) => rowMap.get(id))
1287	+    .filter((r): r is InsightRow => r !== undefined)
1288	+    .map((r) => {
1289	+      let bullets: string[] = [];
1290	+      try { bullets = JSON.parse(r.bullets) as string[]; } catch { /* empty */ }
1291	+      return { id: r.id, type: r.type, summary: r.summary, content: r.content, bullets };
1292	+    });
1293	+
1294	+  const systemPrompt = buildDispatchSystemPrompt(tone);
1295	+  const userMessage = buildDispatchContext({ userContext: contextText, insights: orderedInsights });
1296	+
1297	+  const client = createLLMClient();
1298	+  const messages = [
1299	+    { role: 'user' as const, content: userMessage },
1300	+  ];
1301	+
1302	+  let response = await client.chat(messages, {
1303	+    // temperature 0.7 is not a universal option in the LLMClient interface;
1304	+    // providers use their own defaults — Sonnet defaults to 1.0
1305	+    // We override via system prompt instructions for consistent output length
1306	+  });
1307	+
1308	+  let parsed = parseDispatchOutput(response.content);
1309	+
1310	+  // Single retry on parse failure
1311	+  if (!parsed.ok) {
1312	+    response = await client.chat(messages);
1313	+    parsed = parseDispatchOutput(response.content);
1314	+
1315	+    if (!parsed.ok) {
1316	+      // Degrade gracefully — return the raw content with extracted title
1317	+      parsed = buildDegradedResponse(response.content);
1318	+    }
1319	+  }
1320	+
1321	+  const markdown = parsed.markdown ?? response.content;
1322	+  const wordCount = countWords(markdown);
1323	+
1324	+  return c.json({
1325	+    markdown,
1326	+    frontmatter: parsed.frontmatter ?? { title: 'Untitled', tags: [], tldr: '' },
1327	+    wordCount,
1328	+    model: client.model,
1329	+    tokensUsed: {
1330	+      input: response.usage?.inputTokens ?? 0,
1331	+      output: response.usage?.outputTokens ?? 0,
1332	+    },
1333	+  });
1334	+});
1335	+
1336	+export default app;
