+tags: [sqlite]
+tldr: "A summary."
+---
+
+## Section
+
+Body text.`;
+    const result = parseDispatchOutput(bad);
+    expect(result.ok).toBe(false);
+    expect(result.error).toBe('malformed-frontmatter');
+  });
+
+  it('returns malformed-frontmatter when tldr is missing', () => {
+    const bad = `---
+title: "Some title"
+tags: [sqlite]
+---
+
+## Section
+
+Body text.`;
+    const result = parseDispatchOutput(bad);
+    expect(result.ok).toBe(false);
+    expect(result.error).toBe('malformed-frontmatter');
